    /** Routes per-index getNet0/setNet0/... calls into $container. */
    public function __call(string $name, array $arguments)
    {

        if (preg_match('/^(get|set)Dev(\d+)$/', $name, $m)) {
            $verb = $m[1];
            $idx = (int) $m[2];
            if ($idx >= 0 && $idx <= 8) {
                $key = 'dev' . $idx;
                if ($verb === 'get') {
                    return $this->container[$key] ?? null;
                }
                $this->container[$key] = $arguments[0] ?? null;
                return $this;
            }
        }
        if (preg_match('/^(get|set)Mp(\d+)$/', $name, $m)) {
            $verb = $m[1];
            $idx = (int) $m[2];
            if ($idx >= 0 && $idx <= 255) {
                $key = 'mp' . $idx;
                if ($verb === 'get') {
                    return $this->container[$key] ?? null;
                }
                $this->container[$key] = $arguments[0] ?? null;
                return $this;
            }
        }
        if (preg_match('/^(get|set)Net(\d+)$/', $name, $m)) {
            $verb = $m[1];
            $idx = (int) $m[2];
            if ($idx >= 0 && $idx <= 31) {
                $key = 'net' . $idx;
                if ($verb === 'get') {
                    return $this->container[$key] ?? null;
                }
                $this->container[$key] = $arguments[0] ?? null;
                return $this;
            }
        }
        if (preg_match('/^(get|set)Unused(\d+)$/', $name, $m)) {
            $verb = $m[1];
            $idx = (int) $m[2];
            if ($idx >= 0 && $idx <= 255) {
                $key = 'unused' . $idx;
                if ($verb === 'get') {
                    return $this->container[$key] ?? null;
                }
                $this->container[$key] = $arguments[0] ?? null;
                return $this;
            }
        }

        throw new \BadMethodCallException(sprintf(
            'Call to undefined method %s::%s()',
            static::class,
            $name,
        ));
    }


